IArea = class()

function IArea:ctor()
    self.minX = 0
    self.maxX = 0
    self.minY = 0
    self.maxY = 0
    self.minZ = 0
    self.maxZ = 0
end

function IArea:init(x1, x2, y1, y2, z1, z2)
    self.minX = math.min(tonumber(x1), tonumber(x2))
    self.maxX = math.max(tonumber(x1), tonumber(x2))
    self.minY = math.min(tonumber(y1), tonumber(y2))
    self.maxY = math.max(tonumber(y1), tonumber(y2))
    self.minZ = math.min(tonumber(z1), tonumber(z2))
    self.maxZ = math.max(tonumber(z1), tonumber(z2))
end

function IArea:initByMatrix(matrix)
    self.minX = math.min(tonumber(matrix[1][1]), tonumber(matrix[2][1]))
    self.maxX = math.max(tonumber(matrix[1][1]), tonumber(matrix[2][1]))
    self.minY = math.min(tonumber(matrix[1][2]), tonumber(matrix[2][2]))
    self.maxY = math.max(tonumber(matrix[1][2]), tonumber(matrix[2][2]))
    self.minZ = math.min(tonumber(matrix[1][3]), tonumber(matrix[2][3]))
    self.maxZ = math.max(tonumber(matrix[1][3]), tonumber(matrix[2][3]))
end

function IArea:initByPos(pos1, pos2)
    self.minX = math.min(pos1.x, pos2.x)
    self.maxX = math.max(pos1.x, pos2.x)
    self.minY = math.min(pos1.y, pos2.y)
    self.maxY = math.max(pos1.y, pos2.y)
    self.minZ = math.min(pos1.z, pos2.z)
    self.maxZ = math.max(pos1.z, pos2.z)
end

function IArea:inArea(pos)
    return pos.x >= self.minX and pos.x < self.maxX
            and pos.y >= self.minY and pos.y < self.maxY
            and pos.z >= self.minZ and pos.z < self.maxZ
end

function IArea:inAreaXZ(pos)
    return pos.x >= self.minX and pos.x < self.maxX
            and pos.z >= self.minZ and pos.z < self.maxZ
end

function IArea:getMinPos()
    return VectorUtil.newVector3(self.minX, self.minY, self.minZ)
end

function IArea:getMaxPos()
    return VectorUtil.newVector3(self.maxX, self.maxY, self.maxZ)
end

function IArea:getMinBlockPos()
    return VectorUtil.newVector3i(self.minX, self.minY, self.minZ)
end

function IArea:getMaxBlockPos()
    return VectorUtil.newVector3i(self.maxX, self.maxY, self.maxZ)
end

function IArea:getOverlapArea(area, class)
    local minX = math.max(tonumber(self.minX), tonumber(area.minX))
    local maxX = math.min(tonumber(self.maxX), tonumber(area.maxX))
    local minY = math.max(tonumber(self.minY), tonumber(area.minY))
    local maxY = math.min(tonumber(self.maxY), tonumber(area.maxY))
    local minZ = math.max(tonumber(self.minZ), tonumber(area.minZ))
    local maxZ = math.min(tonumber(self.maxZ), tonumber(area.maxZ))
    if minX > maxX or minY > maxY or minZ > maxZ then
        print("not OverlapArea")
        return nil
    end
    class = class or IArea
    local overlap = class.new()
    overlap:init(minX, maxX, minY, maxY, minZ, maxZ)
    return overlap
end

return IArea